import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

var barCount = 10000

// Smooth-ish random heights so the dense column band has visible structure.
function generateBars(count) {
  var data = new Array(count)
  var y = 60
  for (var i = 0; i < count; i++) {
    y += (Math.random() - 0.5) * 12
    if (y < 10) y = 10
    if (y > 100) y = 100
    data[i] = { x: i, y: Math.round(y) }
  }
  return data
}

var barData = generateBars(barCount)

// Stateless helper shared by the vanilla, React and Vue builds. The chart-bound
// updateStats (and its lastRenderMs) live in each per-format script instead,
// since they read the live instance and per-render timing.
function domNodeCount() {
  var el = document.querySelector('#chart')
  return el ? el.getElementsByTagName('*').length : 0
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [{ name: 'Value', data: barData }],
    options: {
      chart: {
        height: 480,
        type: 'bar',
        renderer: 'canvas',
        rendererThreshold: 8000,
        animations: { enabled: false },
        zoom: { enabled: true, type: 'x', autoScaleYaxis: true },
        toolbar: { autoSelected: 'zoom' },
      },
      plotOptions: {
        bar: { columnWidth: '90%' },
      },
      dataLabels: { enabled: false },
      colors: ['#008FFB'],
      title: {
        text: 'Column chart: 10,000 bars on the canvas renderer',
        align: 'left',
      },
      subtitle: {
        text: 'Bar bodies paint to a canvas layer; axes, grid, zoom and tooltip stay SVG (data labels off at this density)',
        align: 'left',
      },
      xaxis: {
        type: 'numeric',
        tickAmount: 10,
        labels: {
          formatter: function (val) {
            return parseFloat(val).toFixed(0)
          },
        },
      },
      tooltip: { shared: true, intersect: false },
    },
  })

  React.useEffect(() => {
    // This demo destroys and recreates the chart instance on every control change,
    // so it skips the react-apexcharts wrapper and creates the instance in #chart
    // directly, exactly like the vanilla build. barCount, barData, generateBars
    // and domNodeCount live in the shared head script.
    let lastRenderMs = 0
    let chart = null
    let disposed = false

    // The vanilla build gets a mutable `options` global from the template; rebuild
    // it here from the parsed chart state (copy the sub-objects we mutate so the
    // component state is left untouched).
    const options = Object.assign({ series: state.series }, state.options)
    options.chart = Object.assign({}, state.options.chart)
    options.title = Object.assign({}, state.options.title)

    function updateStats() {
      const el = document.getElementById('stats')
      if (!el || !chart) return
      const active = chart.getActiveRenderer ? chart.getActiveRenderer() : 'svg'
      el.innerHTML =
        'Bars: <b>' +
        barCount.toLocaleString() +
        '</b> &nbsp;·&nbsp; Active renderer: <b>' +
        active.toUpperCase() +
        '</b> &nbsp;·&nbsp; DOM nodes in chart: <b>' +
        domNodeCount().toLocaleString() +
        '</b> &nbsp;·&nbsp; Render: <b>' +
        (lastRenderMs > 0
          ? lastRenderMs + ' ms'
          : 'change a control to time it') +
        '</b>'
    }

    function rebuild() {
      barCount = parseInt(document.getElementById('barCount').value, 10)
      const mode = document.getElementById('rendererMode').value

      barData = generateBars(barCount)
      options.chart.renderer = mode
      options.series = [{ name: 'Value', data: barData }]
      options.title.text =
        'Column chart: ' +
        barCount.toLocaleString() +
        ' bars on the ' +
        (mode === 'auto' ? 'auto-selected' : mode) +
        ' renderer'

      const t = performance.now()
      if (chart) chart.destroy()
      chart = new ApexCharts(document.querySelector('#chart'), options)
      chart.render().then(function () {
        if (disposed) return
        lastRenderMs = Math.round(performance.now() - t)
        updateStats()
      })
    }

    document.getElementById('rerender').addEventListener('click', rebuild)
    document.getElementById('rendererMode').addEventListener('change', rebuild)
    document.getElementById('barCount').addEventListener('change', rebuild)
    document.getElementById('resetZoom').addEventListener('click', function () {
      if (chart) chart.resetSeries(true, true)
    })

    // Initial render into #chart, then fill in the live metrics.
    chart = new ApexCharts(document.querySelector('#chart'), options)
    chart.render().then(function () {
      if (disposed) return
      updateStats()
    })

    return () => {
      disposed = true
      if (chart) chart.destroy()
    }
  }, [])

  return (
    <div>
      <div className="panel">
        <div className="controls">
          <label>
            Renderer:
            <select id="rendererMode">
              <option value="canvas" selected>
                canvas
              </option>
              <option value="svg">svg</option>
              <option value="auto">auto</option>
            </select>
          </label>
          <label>
            Bars:
            <select id="barCount">
              <option value="2000">2,000</option>
              <option value="10000" selected>
                10,000
              </option>
              <option value="50000">50,000</option>
              <option value="100000">100,000</option>
            </select>
          </label>
          <button id="rerender">Re-render</button>
          <button id="resetZoom">Reset zoom</button>
        </div>

        <div className="stats" id="stats"></div>

        <div className="note">
          The bar bodies are painted into a single <code>&lt;canvas&gt;</code>{' '}
          while the axes, grid, zoom, and shared tooltip stay as SVG. Zooming
          auto-scales the y-axis to the visible bars while keeping the 0
          baseline (via
          <code>zoom.autoScaleYaxis: true</code>), so the bars still read as
          magnitude.
          <b>Data labels stay SVG</b>
          (the hybrid keeps chrome as SVG), so they are turned off here: 10,000
          labels would be one DOM node each and unreadable at this density. With
          that,
          <b>renderer: 'auto'</b> promotes columns only at 50,000 bars, so this
          demo selects <b>canvas</b> explicitly. Switch to <b>svg</b> at 50,000+
          bars to feel the difference: one node per bar instead of a few dozen
          total.
        </div>
      </div>

      <div id="chart"></div>
    </div>
  )
}

export default ApexChart

#chart {
  max-width: 1000px;
  margin: 20px auto;
}
